module multi_pipe_4bit
#(
    parameter size = 4
)
(
    input clk,
    input rst_n,
    input mul_a,
    input mul_b,
    output reg mul_out
);
    parameter size = 4;
    reg [3:0] reg_a, reg_b;
    reg [7:0] reg_s [size-1:0];
    reg [7:0] reg_c [size-1:0];
    reg [7:0] reg_p;
    always @(*) begin
        reg_a = {4'b0, mul_a};
        reg_b = {4'b0, mul_b};
    end
    genvar i;
    generate
        for (i = 0; i < size; i = i + 1) begin : gen
            wire [7:0] pp;
            assign pp = reg_b[i] ? (reg_a << i) : 'd0;
            always @(posedge clk or negedge rst_n) begin
                if (!rst_n) begin
                    reg_s[i] <= 8'b0;
                    reg_c[i] <= 8'b0;
                end else begin
                    reg_s[i] <= pp;
                    reg_c[i] <= reg_c[i-1];
                end
            end
        end
    endgenerate
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            reg_p <= 8'b0;
        end else begin
            reg_p <= reg_c[size-1];
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_out <= 8'b0;
        end else begin
            mul_out <= reg_p + reg_s[size-1];
        end
    end
endmodule
